import { icons } from '@iconify-json/fluent';
import { readFileSync, writeFileSync } from 'node:fs';

const mapSource = readFileSync(new URL('../src/lib/icons/fluent-map.ts', import.meta.url), 'utf8');
const ids = [...mapSource.matchAll(/:\s*'([^']+)'/g)].map((match) => match[1]);
const uniqueIds = [...new Set(ids)];
const missingIds = uniqueIds.filter((id) => !icons.icons[id]);
if (missingIds.length) throw new Error(`Missing Fluent icons: ${missingIds.join(', ')}`);

const lines = [
  '/** Generated by scripts/generate-fluent-icons.mjs. Do not edit manually. */',
  '',
  'export const FLUENT_ICON_COLLECTION = {',
  "\tprefix: 'fluent',",
  '\ticons: {'
];
for (const id of uniqueIds) lines.push(`\t\t${JSON.stringify(id)}: ${JSON.stringify(icons.icons[id])},`);
lines.push('\t}', '} as const;', '', `export const FLUENT_ICON_IDS = ${JSON.stringify(uniqueIds)} as const;`, '');
writeFileSync(new URL('../src/lib/icons/fluent-icons.ts', import.meta.url), lines.join('\n'));
console.log(`Generated ${uniqueIds.length} Fluent icons`);
